features.snippet:
module rom(input clk, input [2:0] addr,
(* ram_style = "block" *)
output reg [7:0] data);
always @(posedge clk)
case (addr)
3'b000: data <= 8'h12;
3'b001: data <= 8'hAB;
3'b010: data <= 8'h42;
3'b011: data <= 8'h23;
3'b100: data <= 8'h66;
3'b101: data <= 8'hC0;
3'b110: data <= 8'h3F;
3'b111: data <= 8'h95;
endcase
endmodule
